using System.ComponentModel.DataAnnotations;

namespace sv_f283569dd736427ba7ba788afcbf1d62.Models;

public class Product
{
    public int Id { get; set; }

    [Required(ErrorMessage = "Name is required.")]
    public string Name { get; set; } = string.Empty;

    [Range(0, 9999, ErrorMessage = "Quantity must be between 0 and 9999.")]
    public int Quantity { get; set; }

    [Range(0.01, double.MaxValue, ErrorMessage = "Unit Price must be greater than 0.")]
    public decimal UnitPrice { get; set; }

    [Required(ErrorMessage = "Category is required.")]
    public string Category { get; set; } = string.Empty;
}

using sv_f283569dd736427ba7ba788afcbf1d62.Models;

namespace sv_f283569dd736427ba7ba788afcbf1d62.Services;

public class InventoryService
{
    private readonly List<Product> _products = new()
    {
        new Product { Id = 1, Name = "Wireless Mouse", Quantity = 150, UnitPrice = 29.99m, Category = "Electronics" },
        new Product { Id = 2, Name = "Cotton T-Shirt", Quantity = 300, UnitPrice = 14.50m, Category = "Clothing" },
        new Product { Id = 3, Name = "Organic Coffee Beans", Quantity = 80, UnitPrice = 12.99m, Category = "Food" },
        new Product { Id = 4, Name = "USB-C Hub", Quantity = 60, UnitPrice = 49.95m, Category = "Electronics" },
        new Product { Id = 5, Name = "Winter Jacket", Quantity = 45, UnitPrice = 89.00m, Category = "Clothing" },
        new Product { Id = 6, Name = "Notebook & Pen Set", Quantity = 200, UnitPrice = 7.25m, Category = "Other" }
    };

    private readonly Lock _lock = new();

    public Task<List<Product>> GetAllAsync()
    {
        lock (_lock)
        {
            var copy = _products.Select(p => new Product
            {
                Id = p.Id,
                Name = p.Name,
                Quantity = p.Quantity,
                UnitPrice = p.UnitPrice,
                Category = p.Category
            }).ToList();
            return Task.FromResult(copy);
        }
    }

    public Task UpdateAsync(Product product)
    {
        lock (_lock)
        {
            var existing = _products.FirstOrDefault(p => p.Id == product.Id);
            if (existing is not null)
            {
                existing.Name = product.Name;
                existing.Quantity = product.Quantity;
                existing.UnitPrice = product.UnitPrice;
                existing.Category = product.Category;
            }
        }
        return Task.CompletedTask;
    }
}

@page "/inventory"
@rendermode InteractiveServer
@using sv_f283569dd736427ba7ba788afcbf1d62.Models
@using sv_f283569dd736427ba7ba788afcbf1d62.Services
@inject InventoryService InventoryService

<PageTitle>Inventory</PageTitle>

<h1>Inventory</h1>

@if (products is null)
{
    <p>Loading...</p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Name</th>
                <th>Quantity</th>
                <th>Unit Price</th>
                <th>Category</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var product in products)
            {
                @if (editingProductId == product.Id)
                {
                    <tr>
                        <td>
                            <EditForm EditContext="editContext" OnValidSubmit="SaveAsync" FormName="editProduct">
                                <DataAnnotationsValidator />
                                <InputText @bind-Value="editModel!.Name" class="form-control" />
                                <ValidationMessage For="() => editModel!.Name" />
                            </EditForm>
                        </td>
                        <td>
                            <InputNumber @bind-Value="editModel!.Quantity" class="form-control" form="editProduct" />
                            <ValidationMessage For="() => editModel!.Quantity" />
                        </td>
                        <td>
                            <InputNumber @bind-Value="editModel!.UnitPrice" class="form-control" form="editProduct" />
                            <ValidationMessage For="() => editModel!.UnitPrice" />
                        </td>
                        <td>
                            <InputSelect @bind-Value="editModel!.Category" class="form-control" form="editProduct">
                                <option value="">-- Select --</option>
                                @foreach (var cat in Categories)
                                {
                                    <option value="@cat">@cat</option>
                                }
                            </InputSelect>
                            <ValidationMessage For="() => editModel!.Category" />
                        </td>
                        <td>
                            <button class="btn btn-success btn-sm" @onclick="SaveAsync">Save</button>
                            <button class="btn btn-secondary btn-sm" @onclick="Cancel">Cancel</button>
                        </td>
                    </tr>
                }
                else
                {
                    <tr>
                        <td>@product.Name</td>
                        <td>@product.Quantity</td>
                        <td>@product.UnitPrice.ToString("C")</td>
                        <td>@product.Category</td>
                        <td>
                            <button class="btn btn-primary btn-sm" @onclick="() => Edit(product)">Edit</button>
                        </td>
                    </tr>
                }
            }
        </tbody>
    </table>
}

@code {
    private static readonly string[] Categories = { "Electronics", "Clothing", "Food", "Other" };

    private List<Product>? products;
    private int? editingProductId;
    private Product? editModel;
    private EditContext? editContext;

    protected override async Task OnInitializedAsync()
    {
        products = await InventoryService.GetAllAsync();
    }

    private void Edit(Product product)
    {
        editingProductId = product.Id;
        editModel = new Product
        {
            Id = product.Id,
            Name = product.Name,
            Quantity = product.Quantity,
            UnitPrice = product.UnitPrice,
            Category = product.Category
        };
        editContext = new EditContext(editModel);
    }

    private async Task SaveAsync()
    {
        if (editContext is null || editModel is null) return;

        if (!editContext.Validate()) return;

        await InventoryService.UpdateAsync(editModel);
        var existing = products!.First(p => p.Id == editModel.Id);
        existing.Name = editModel.Name;
        existing.Quantity = editModel.Quantity;
        existing.UnitPrice = editModel.UnitPrice;
        existing.Category = editModel.Category;

        editingProductId = null;
        editModel = null;
        editContext = null;
    }

    private void Cancel()
    {
        editingProductId = null;
        editModel = null;
        editContext = null;
    }
}

